import{_ as e,o as a,c as l,a2 as r}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"01-1 貨櫃航運產業結構","description":"","frontmatter":{},"headers":[],"relativePath":"Deep32Q知識庫/產業洞察/航運產業/01_次產業結構/01-1_貨櫃航運.md","filePath":"Deep32Q知識庫/產業洞察/航運產業/01_次產業結構/01-1_貨櫃航運.md"}'),n={name:"Deep32Q知識庫/產業洞察/航運產業/01_次產業結構/01-1_貨櫃航運.md"};function i(o,t,d,s,c,g){return a(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="_01-1-貨櫃航運產業結構" tabindex="-1">01-1 貨櫃航運產業結構 <a class="header-anchor" href="#_01-1-貨櫃航運產業結構" aria-label="Permalink to &quot;01-1 貨櫃航運產業結構&quot;">​</a></h1><h2 id="一、三大聯盟格局-2025-2026" tabindex="-1">一、三大聯盟格局（2025-2026） <a class="header-anchor" href="#一、三大聯盟格局-2025-2026" aria-label="Permalink to &quot;一、三大聯盟格局（2025-2026）&quot;">​</a></h2><p>貨櫃航運自 2M 聯盟解體後，全球格局重組為三大聯盟體系：</p><h3 id="_1-gemini-cooperation-新聯盟" tabindex="-1">1. Gemini Cooperation（新聯盟） <a class="header-anchor" href="#_1-gemini-cooperation-新聯盟" aria-label="Permalink to &quot;1. Gemini Cooperation（新聯盟）&quot;">​</a></h3><ul><li><strong>成員</strong>：Maersk + Hapag-Lloyd</li><li><strong>啟動時間</strong>：2025 年 2 月（取代原 2M）</li><li><strong>規模</strong>：約 340 艘船，總運能約 370 萬 TEU</li><li><strong>分工</strong>：Maersk 提供 60% 運能，Hapag-Lloyd 提供 40%</li><li><strong>營運模式</strong>：東西向航線主幹，採用樞紐輻輳（hub-and-spoke）模式</li></ul><h3 id="_2-ocean-alliance" tabindex="-1">2. Ocean Alliance <a class="header-anchor" href="#_2-ocean-alliance" aria-label="Permalink to &quot;2. Ocean Alliance&quot;">​</a></h3><ul><li><strong>成員</strong>：CMA CGM、COSCO Group（含 OOCL）、Evergreen Marine</li><li><strong>市佔率</strong>：約 29%</li><li><strong>協議期限</strong>：已延長至 2032 年</li><li><strong>規模</strong>：2026 年網路部署 394 艘船，總載運力 530 萬 TEU</li></ul><h3 id="_3-premier-alliance-原-the-alliance" tabindex="-1">3. Premier Alliance（原 THE Alliance） <a class="header-anchor" href="#_3-premier-alliance-原-the-alliance" aria-label="Permalink to &quot;3. Premier Alliance（原 THE Alliance）&quot;">​</a></h3><ul><li><strong>成員</strong>：ONE、HMM、Yang Ming</li><li><strong>市佔率</strong>：約 12%</li><li><strong>轉型</strong>：Hapag-Lloyd 退出後，於 2025 年 2 月更名為 Premier Alliance</li><li><strong>定位</strong>：東西向航線，強調彈性與反應速度</li></ul><h3 id="獨立營運" tabindex="-1">獨立營運 <a class="header-anchor" href="#獨立營運" aria-label="Permalink to &quot;獨立營運&quot;">​</a></h3><ul><li><strong>MSC</strong>：全球最大貨櫃航商，2M 解體後獨立營運，市佔約 21.6%（2026 年 4 月）</li><li>MSC 亦與 ZIM 簽訂跨太平洋長期航線合作協議（2025 年 2 月起）</li></ul><h2 id="二、前十大航商市佔率-2026-年-4-月數據" tabindex="-1">二、前十大航商市佔率（2026 年 4 月數據） <a class="header-anchor" href="#二、前十大航商市佔率-2026-年-4-月數據" aria-label="Permalink to &quot;二、前十大航商市佔率（2026 年 4 月數據）&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:center;">排名</th><th>公司</th><th style="text-align:center;">市佔率</th><th>聯盟歸屬</th></tr></thead><tbody><tr><td style="text-align:center;">1</td><td>MSC（地中海航運）</td><td style="text-align:center;">21.6%</td><td>獨立營運</td></tr><tr><td style="text-align:center;">2</td><td>Maersk（馬士基）</td><td style="text-align:center;">13.7%</td><td>Gemini Cooperation</td></tr><tr><td style="text-align:center;">3</td><td>CMA CGM（達飛）</td><td style="text-align:center;">12.6%</td><td>Ocean Alliance</td></tr><tr><td style="text-align:center;">4</td><td>COSCO Shipping Lines（中遠海運）</td><td style="text-align:center;">10.6%</td><td>Ocean Alliance</td></tr><tr><td style="text-align:center;">5</td><td>Hapag-Lloyd（赫伯羅特）</td><td style="text-align:center;">7.1%</td><td>Gemini Cooperation</td></tr><tr><td style="text-align:center;">6</td><td>ONE（長榮海運合資）</td><td style="text-align:center;">~6.3%</td><td>Premier Alliance</td></tr><tr><td style="text-align:center;">7</td><td>Evergreen（長榮海運）</td><td style="text-align:center;">5.8%</td><td>Ocean Alliance</td></tr><tr><td style="text-align:center;">8</td><td>HMM（韓進）</td><td style="text-align:center;">~3.0%</td><td>Premier Alliance</td></tr><tr><td style="text-align:center;">9</td><td>Yang Ming（陽明海運）</td><td style="text-align:center;">~2.2%</td><td>Premier Alliance</td></tr><tr><td style="text-align:center;">10</td><td>ZIM（以色列表決）</td><td style="text-align:center;">~2.1%</td><td>獨立（與 MSC 跨太平洋合作）</td></tr></tbody></table><blockquote><p>資料來源：Freightender、Container-News.com、GB-Freight.com（2026 年 4 月數據）</p></blockquote><h2 id="三、主要航線結構" tabindex="-1">三、主要航線結構 <a class="header-anchor" href="#三、主要航線結構" aria-label="Permalink to &quot;三、主要航線結構&quot;">​</a></h2><h3 id="東西向主幹航線" tabindex="-1">東西向主幹航線 <a class="header-anchor" href="#東西向主幹航線" aria-label="Permalink to &quot;東西向主幹航線&quot;">​</a></h3><ul><li><strong>亞洲—北美西岸</strong>：上海/寧波→洛杉磯/長灘，為全球最繁忙跨太平洋航線</li><li><strong>亞洲—北美東岸</strong>：經巴拿馬運河或好望角至紐約/薩凡納</li><li><strong>亞洲—歐洲</strong>：上海→鹿特丹/漢堡，跨印度洋、紅海、地中海</li><li><strong>歐洲—北美</strong>：橫跨大西洋的雙向航線</li></ul><h3 id="區域性航線" tabindex="-1">區域性航線 <a class="header-anchor" href="#區域性航線" aria-label="Permalink to &quot;區域性航線&quot;">​</a></h3><ul><li>東南亞內部、中東—非洲、南美—亞洲等</li></ul><h2 id="四、單位說明" tabindex="-1">四、單位說明 <a class="header-anchor" href="#四、單位說明" aria-label="Permalink to &quot;四、單位說明&quot;">​</a></h2><ul><li><strong>TEU</strong>（Twenty-foot Equivalent Unit）：標準貨櫃單位，以 20 呎貨櫃為基準</li><li><strong>FEU</strong>（Forty-foot Equivalent Unit）：40 呎貨櫃，等於 2 TEU</li></ul><h2 id="五、運價指數簡介" tabindex="-1">五、運價指數簡介 <a class="header-anchor" href="#五、運價指數簡介" aria-label="Permalink to &quot;五、運價指數簡介&quot;">​</a></h2><ul><li><strong>SCFI</strong>（Shanghai Containerized Freight Index，上海出口貨櫃運價指數）：由上海航交所每週發布，反映上海出發至全球主要港口的即期運價。涵蓋 20 條航線，以美元計價。</li><li><strong>CCFI</strong>（China Containerized Freight Index，中國出口貨櫃綜合運價指數）：由上海航交所發布，涵蓋更多航線與港口，以加權平均方式計算綜合指數。</li></ul><blockquote><p>資料來源：Freightender（2025-2026）、Container-News.com 貨櫃航商排名、GB-Freight.com（2026 年 4 月）、Wikipedia — Gemini Cooperation、Flexport 新聞稿</p></blockquote>',24)])])}const x=e(n,[["render",i]]);export{u as __pageData,x as default};
